-- FSI_DEMO_DB.INSURANCE.RISK_ASSESSMENTS

CREATE OR REPLACE TABLE FSI_DEMO_DB.INSURANCE.RISK_ASSESSMENTS (

    ASSESSMENT_ID VARCHAR(20) NOT NULL,
    POLICYHOLDER_ID VARCHAR(20),
    ASSESSMENT_DATE DATE,
    ASSESSMENT_TYPE VARCHAR(50),
    UNDERWRITER_ID VARCHAR(20),
    HEALTH_SCORE NUMBER(3,0),
    LIFESTYLE_RISK VARCHAR(30),
    OCCUPATION_RISK VARCHAR(30),
    LOCATION_RISK VARCHAR(30),
    PRIOR_CLAIMS_COUNT NUMBER(5,0),
    PRIOR_CLAIMS_AMOUNT NUMBER(15,2),
    CREDIT_BASED_SCORE NUMBER(3,0),
    OVERALL_RISK_GRADE VARCHAR(5),
    RECOMMENDATION VARCHAR(500),
    NOTES VARCHAR(16777216),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (ASSESSMENT_ID)

);


